class Solution(object):
    def numRookCaptures(self, board):
        result = 0
        r, c = 0, 0
        for i in range(8):
            for j in range(8):
                if board[i][j] == 'R':
                    r, c = i, j
                    break
        for direction in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            nr, nc = r, c
            while 0 <= nr < 8 and 0 <= nc < 8:
                if board[nr][nc] == 'B':
                    break
                if board[nr][nc] == 'p':
                    result += 1
                    break
                nr += direction[0]
                nc += direction[1]
        return result
